void ApplySubclassDefaults()
    {
        // 전부 해제
        foreach (var e in _skillEntries) e.Toggle.isOn = false;
        foreach (var e in _passiveEntries) e.Toggle.isOn = false;

        if (_subclass == null && _classSO != null)
        {
            // 서브클래스 없으면 기본 StartSkills 선택
            var defaults = _classSO.StartSkills;
            if (defaults != null)
            {
                foreach (var defSkill in defaults)
                {
                    var match = _skillEntries.FirstOrDefault(e =>
                        e.Skill != null && e.Skill.name == defSkill.name);
                    if (match != null) match.Toggle.isOn = true;
                }
            }
            return;
        }

        // 서브클래스 StartSkillOverrides
        if (_subclass.StartSkillOverrides != null && _subclass.StartSkillOverrides.Count > 0)
        {
            foreach (var defSkill in _subclass.StartSkillOverrides)
            {
                if (defSkill == null) continue;
                var match = _skillEntries.FirstOrDefault(e =>
                    e.Skill != null && e.Skill.name == defSkill.name);
                if (match != null) match.Toggle.isOn = true;
            }
        }
        else if (_classSO != null && _classSO.StartSkills != null)
        {
            // Override 없으면 ClassSO 기본 StartSkills
            foreach (var defSkill in _classSO.StartSkills)
            {
                var match = _skillEntries.FirstOrDefault(e =>
                    e.Skill != null && e.Skill.name == defSkill.name);
                if (match != null) match.Toggle.isOn = true;
            }
        }

        // 서브클래스 StartPassiveOverrides
        if (_subclass.StartPassiveOverrides != null)
        {
            foreach (var defPassive in _subclass.StartPassiveOverrides)
            {
                if (defPassive == null) continue;
                var match = _passiveEntries.FirstOrDefault(e =>
                    e.Passive != null && e.Passive.name == defPassive.name);
                if (match != null) match.Toggle.isOn = true;
            }
        }

        UpdateBudgetDisplay();
    }

