public void OnRewardSelected()
    {
        // ✅ [AUD-Anti] 1회용 완료 콜백 실행 (SkillScholar 등에서 OnNodeCompleted 지연)
        if (OnRewardDoneCallback != null)
        {
            var done = OnRewardDoneCallback;
            OnRewardDoneCallback = null;
            done.Invoke();
        }

        // ✅ [Round 120] 보스 격파 특별 보상 후 처리 — OnPostBossRewardComplete 콜백 우선
        // 보스전 후 특별 보상을 선택했으면 콜백(OnRunComplete 등)을 실행하고 종료
        var tbc = BattleController.Instance;
        if (tbc?.OnPostBossRewardComplete != null)
        {
            var cb = tbc.OnPostBossRewardComplete;
            tbc.OnPostBossRewardComplete = null; // 1회 소비
            cb.Invoke();
            return; // 맵 복귀 생략 — 런 완료 화면으로 이동
        }

        // ✅ 레벨업 큐 — 대기 중인 레벨업이 있으면 맵 복귀 대신 다음 레벨업 처리
        if (_isLevelUpReward && PlayerLevel.Instance != null)
        {
            PlayerLevel.Instance.OnLevelUpRewardComplete();
            // ProcessNextLevelUp()이 ShowRewards를 다시 호출했으면 여기서 리턴
            // 큐가 비었으면 맵 복귀로 진행
            if (gameObject.activeSelf) return; // RewardUI가 다시 열렸으면 리턴
        }

        // ✅ [AUD-CDX-88001] NodeExecutor null 시 완료 라이프사이클 보장
        if (NodeExecutor.Instance != null)
        {
            NodeExecutor.Instance.ReturnToMap();
            // ReturnToMap이 OnEncounterCompleted + ShowMapPanel/ShowMap까지 처리하므로 이후 호출 없음
        }
        else
        {
            GameFlow.Instance?.OnEncounterCompleted(
                MapIntegration.Instance?.NodesCompleted ?? 0);
            if (GameFlow.Instance != null)
                GameFlow.Instance.ShowMapPanel();
            else
            {
                // ✅ [AUD-CDX-20602 Fix] GameFlow null 폴백에서 pause 해제 보장
                MapManager.Instance?.EndNodeInteractionPause();
                MapUI.Instance?.ShowMap();
            }
        }
    }

void OnStartRun()
    {
        // [AUD-CDX-31034] 재진입 방지 — 빠른 이중 클릭 시 환전/소모품 중복 실행 차단
        if (_isStarting) return;
        _isStarting = true;

        // 환전 처리 — [AUD-CDX-31027] 명시적 확인(Confirm) 시에만 실행
        if (_exchangeConfirmed && tokensToExchange > 0 && ExchangeSystem != null)
        {
            ExchangeSystem.ExchangeForRun(tokensToExchange);
        }
        tokensToExchange = 0;
        _exchangeConfirmed = false;

        // UI 닫기
        gameObject.SetActive(false);

        // ✅ [Round 46] 소모품 즉시 효과 적용 (StartLevel3 XP, ShieldStart 실드, SkipToBoss 등)
        ConsumableSystem?.ApplyConsumables();

#if UNITY_EDITOR || DEVELOPMENT_BUILD
        // ✅ 기지 전략 디버그 프리셋 (BaseLobbyUI 미구현 기간 테스트용)
        //    BaseStrategyManager Inspector에서 DebugPresetEnabled = true 설정 시 동작
        BaseStrategyManager.Instance?.ApplyDebugPreset();
#endif

        // ✅ RunStartFlow에 알림
        var runFlow = RunStartFlow.Instance;
        if (runFlow != null)
        {
            runFlow.OnRunStartComplete();
        }
        else
        {
            // Fallback: 직접 게임 시작
            var gameFlow = GameFlow.Instance;
            if (gameFlow != null)
            {
                gameFlow.StartRun();
            }
        }
    }

