private static bool RerollSkill(CharacterBase c)
    {
        var skillbook = c.GetComponent<PlayerSkillbook>();
        if (skillbook == null) skillbook = PlayerSkillbook.Instance;

        if (skillbook != null && skillbook.Skills != null && skillbook.Skills.Count > 0)
        {
            // ✅ [Fix] 실제 리롤 구현 — 랜덤 스킬 1개 제거 후 새 스킬 습득 기회 부여
            var removeTarget = skillbook.Skills[Random.Range(0, skillbook.Skills.Count)];
            string removedName = removeTarget.name;

            // 스킬 제거
            skillbook.Skills.Remove(removeTarget);

            // 로드아웃에서도 제거
            if (skillbook.ActiveLoadout != null)
            {
                for (int i = 0; i < skillbook.ActiveLoadout.Count; i++)
                {
                    if (skillbook.ActiveLoadout[i] == removeTarget)
                        skillbook.ActiveLoadout[i] = null;
                }
            }

            // KnownSkills에서도 제거
            if (skillbook.KnownSkills != null)
                skillbook.KnownSkills.Remove(removeTarget);

            // 새 랜덤 스킬 추가 시도 (풀에서 미보유 스킬)
            // ✅ [AUD-022-L003] 정적 캐시 사용 — Resources.LoadAll 반복 호출 방지
            if (_cachedAllSkills == null || _cachedAllSkills.Length == 0)
                _cachedAllSkills = Resources.LoadAll<SkillDefinitionSO>("Skills");
            var allSkills = _cachedAllSkills;
            var candidates = new System.Collections.Generic.List<SkillDefinitionSO>();
            foreach (var s in allSkills)
            {
                if (!skillbook.Skills.Contains(s) && s != removeTarget)
                    candidates.Add(s);
            }

            if (candidates.Count > 0)
            {
                var newSkill = candidates[Random.Range(0, candidates.Count)];
                skillbook.Skills.Add(newSkill);
                if (skillbook.KnownSkills != null)
                    skillbook.KnownSkills.Add(newSkill);

                // 빈 로드아웃 슬롯에 자동 배치
                if (skillbook.ActiveLoadout != null)
                {
                    for (int i = 0; i < skillbook.ActiveLoadout.Count; i++)
                    {
                        if (skillbook.ActiveLoadout[i] == null)
                        {
                            skillbook.ActiveLoadout[i] = newSkill;
                            break;
                        }
                    }
                }

                ShowFeedback($"'{removedName}' → '{newSkill.name}'", Color.cyan);
                Debug.Log($"[ItemEffect] RerollSkill → removed '{removedName}', added '{newSkill.name}'");
            }
            else
            {
                ShowFeedback($"'{removedName}' removed (no replacement)", Color.yellow);
                Debug.Log($"[ItemEffect] RerollSkill → removed '{removedName}', no candidates for replacement");
            }

            return true;
        }

        ShowFeedback("No skills to reroll", Color.gray);
        return false;
    }

public void ApplyPendingBaseDish()
    {
        if (PendingBaseDish == null) return;

        var cs = CookingSystem.Instance;
        if (cs == null)
        {
            // ★ [2026-06-14 Codex P2] CookingSystem 미초기화 시 ★삭제하지 말고 보류★ — 기존엔 ClearPendingBaseDish 로
            //   대기 요리를 적용 못 한 채 영구 삭제(직접 손실)했다. 다음 시작에서 재시도하도록 그대로 둔다.
            Debug.LogWarning("[CookingSynthesizer] CookingSystem not found — PendingBaseDish 적용 보류(다음 시작 재시도, 삭제 안 함)");
            return;
        }

        cs.AddDurationGroupedBuffsAndNotify("SYNTH_BASE", PendingBaseDish.Name, PendingBaseDish.Effects);
        Debug.Log($"[CookingSynthesizer] PendingBaseDish applied: {PendingBaseDish.Name}");

        // 즉시 효과 적용
        ApplyImmediateEffects(PendingBaseDish);

        // ★ [2026-06-14 Codex P2] 적용된 버프를 미드런 스냅샷에 ★커밋한 뒤★ 대기요리 삭제 — 기존엔 삭제(영속 커밋) 직후 force
        //   스냅샷이 없어, 런 시작 직후 종료 시 '대기요리 삭제됨 + 버프 미스냅샷 = 영구 손실'. force 스냅샷이 ExportMidRunBuffs 로
        //   버프를 영속(맵은 GenerateMap 이 CommonRunInit 전이라 이미 존재 → 조기 스냅샷 아님). 그 ★뒤★ 대기요리 소비.
        GameFlow.Instance?.RequestMidRunSnapshot("PendingBaseDishApplied", force: true);

        ClearPendingBaseDish();
    }

