private void OnUnlockAISkill(SkillDefinitionSO skill, int price)
        {
            int currentLevel = PlayerLevel.Instance?.Level ?? 1;
            if (skill != null && skill.UnlockLevel > currentLevel)
            {
                ShowMessage(Loc.Fmt("Skill/SkillMasterControllerComplete/L226", skill.UnlockLevel)); // 레벨 부족 (필요: Lv.{skill.UnlockLevel})
                return;
            }

            // ✅ [AUD-09004] GoldManager.CanAfford + MapIntegration.SpendGold 불일치 해소
            // MapIntegration.SpendGold 내부에서 GoldManager.CanAfford를 통해 검증 후 GameFlow.AddGold(-price)로 소비
            // 중복 GoldManager.CanAfford 제거 → SpendGold 단일 경로로 통일
            bool success = MapIntegration.Instance?.SpendGold(price) ?? false;
            if (!success)
            {
                ShowMessage(Loc.Fmt("Skill/SkillMasterControllerComplete/L232", price)); // 골드 부족! (필요: {price}G)
                Debug.LogError("[SkillMaster] AI 스킬 골드 차감 실패 (잔액 부족 또는 MapIntegration 없음)");
                return;
            }

            // 플레이어 스킬에 추가
            MapIntegration.Instance?.AddSkill(skill);

            // 카탈로그에서 제거 (중복 구매 방지)
            _aiSkills?.Remove(skill);

            RefreshSkillList();
            UpdateGoldDisplay();
            ShowMessage(Loc.Fmt("Skill/SkillMasterControllerComplete/L251", ResolveSkillDisplayName(skill))); // ✨ [AI 스킬] {skill.NameKey} 획득!
            GameFlow.Instance?.RequestMidRunSnapshot("SkillMaster.OnUnlockAISkill", true);
            Debug.Log($"[SkillMaster] AI 스킬 언락: {skill.NameKey} (-{price}G)");
        }

if (ActiveSynergies.Contains(synergy))
            return;

        ActiveSynergies.Add(synergy);
        ApplySynergyEffects(synergy);

        // [R389] ANOM_ECO_SYNERGY_COUNTER: each synergy trigger drains 5 gold.
        // ✅ [AUD-33301 Fix] 재계산 중(RemoveAll→Recheck)에는 골드 소모 스킵
        if (!_isRecalculating && TRPG.Anomaly.InRunAnomalyManager.IsSynergyCounterActive())
        {
            GameFlow.Instance?.AddGold(-5);
            SaveManager.Instance?.SaveGame(forceImmediate: true); // ✅ [AUD-CDX-100001 Fix] 이변 카운터 골드 드레인 즉시 커밋 — 세이브-스컴 방지
            MsgManager.Instance?.InputInstantMsg(Loc.Get("System/SynergyManager/L235"), InstantMsgType.Error);
        }

private void ApplyInheritedWills(List<LegacyWillEntry> selected)
        {
            _inheritedThisRun = new List<LegacyWillEntry>(selected);

            var player    = PlayerLevel.Instance?.GetComponent<CharacterBase>();
            var relicSys  = player?.GetComponent<RelicEffectSystem>();
            var skillbook = PlayerSkillbook.Instance;

            foreach (var will in selected)
            {
                if (will.Type == LegacyWillEntry.WillType.Relic && relicSys != null)
                {
                    // 유물 이름으로 SO 탐색 (서브폴더 폴백 포함)
                    var relicSO = ResolveRelicBySourceName(will.SourceName);
                    if (relicSO != null)
                    {
                        relicSys.AddRelic(relicSO);
                        Debug.Log($"[LegacyWillSystem] 유언 유물 상속: {will.DisplayName}");
                    }
                    else
                    {
                        Debug.LogWarning($"[LegacyWillSystem] 유물 SO를 찾을 수 없음: {will.SourceName}");
                    }
                }
                else if (will.Type == LegacyWillEntry.WillType.Skill && skillbook != null)
                {
                    // 스킬 이름으로 SO 탐색 (서브폴더 폴백 포함)
                    var skillSO = ResolveSkillBySourceName(will.SourceName);
                    if (skillSO != null)
                    {
                        skillbook.AddSkill(skillSO);
                        Debug.Log($"[LegacyWillSystem] 유언 스킬 상속: {will.DisplayName}");
                    }
                    else
                    {
                        Debug.LogWarning($"[LegacyWillSystem] 스킬 SO를 찾을 수 없음: {will.SourceName}");
                    }
                }

                MsgManager.Instance?.InputInstantMsg(
                    Loc.Fmt("Antigravity/LegacyWillSystem/L286", ResolveMaybeLocalized(will.DisplayName)), // 📜 [유언 상속] '{will.DisplayName}' 전승됨!
                    InstantMsgType.Good);
            }

            // ✅ [InheritedEffectScale] 상속 유물/스킬 적용 후 전투력 보정 적용
            // InheritedEffectScale = 0.7 → 플레이어 PhyPower/MagPower를 70%로 감쇠
            // MultDamage value = scale - 1f = -0.3 → stat *= (1 + (-0.3)) = stat * 0.7
            if (selected.Count > 0 && player != null && InheritedEffectScale < 1f)
            {
                ApplyInheritedScaleModifier(player);
            }
        }

public void OnNodeMoved(NodeType nodeType)
        {
            // 전투 노드가 아닌 경우에만
            if (nodeType == NodeType.Combat || nodeType == NodeType.Elite ||
                nodeType == NodeType.Boss || nodeType == NodeType.MidBoss ||
                nodeType == NodeType.Seal) return;

            foreach (var skill in _activeSkills)
            {
                if (skill.Data == null) continue;
                if (skill.Data.EffectType == FieldSkillEffect.CompanionPartyHeal)
                {
                    // [Fix] NoHealing 수정자 체크
                    if (RunModifierSystem.Instance != null && !RunModifierSystem.Instance.CanHeal())
                    {
                        Debug.Log($"[CompanionFieldSkill] {skill.CompanionName}: 야전 수리 차단 (NoHealing 수정자)");
                        continue;
                    }

                    float healRate = skill.EffectValue; // e.g., 0.03 = 3%
                    var companions = CompanionManager.Instance?.GetActiveCompanions();
                    if (companions == null) continue;

                    // 플레이어 + 동료 전체 회복 (실제 회복량 추적)
                    bool anyHealed = false;
                    var player = PlayerLevel.Instance?.GetComponent<CharacterBase>();
                    if (player != null && player.Stat != null && !player.IsDead())
                    {
                        float hpBefore = player.Stat.HP;
                        int healAmount = Mathf.Max(1, Mathf.RoundToInt(player.Stat.MaxHP * healRate));
                        player.ApplyDeltaHP(healAmount);
                        if (player.Stat.HP > hpBefore) anyHealed = true;
                    }
                    foreach (var comp in companions)
                    {
                        if (comp != null && comp.Stat != null && !comp.IsDead())
                        {
                            float hpBefore = comp.Stat.HP;
                            int healAmount = Mathf.Max(1, Mathf.RoundToInt(comp.Stat.MaxHP * healRate));
                            comp.ApplyDeltaHP(healAmount);
                            if (comp.Stat.HP > hpBefore) anyHealed = true;
                        }
                    }
                    // [Fix] NoHeal 챌린지 — 실제 HP 증가 시에만 기록
                    if (anyHealed)
                        ChallengeRunSystem.Instance?.NotifyHealUsed();
                    Debug.Log($"[CompanionFieldSkill] {skill.CompanionName}: 야전 수리 발동 ({healRate * 100:F0}% HP, healed={anyHealed})");
                }
            }
        }

private void OnClericNodeCompleted(CharacterBase player)
    {
        if (player == null || player.Stat == null) return; // [AUD-709-H002]
        // [Fix] NoHealing 수정자 체크
        if (RunModifierSystem.Instance != null && !RunModifierSystem.Instance.CanHeal()) return;

        float recoverRate = BalanceConfig.INSTINCT_CLERIC_HP_RECOVER * _metaMultiplier;
        int hpRecover = Mathf.Max(1, Mathf.RoundToInt(player.Stat.MaxHP * recoverRate));

        if (player.Stat.HP < player.Stat.MaxHP)
        {
            player.ApplyDeltaHP(hpRecover);
            ChallengeRunSystem.Instance?.NotifyHealUsed();
            MsgManager.Instance?.InputInstantMsg(
                Loc.Fmt("Skill/ClassInstinctSystem/L203", hpRecover), // 💡 [신의 은총] HP +{hpRecover} 회복
                InstantMsgType.Normal);
        }
    }

